export const getStylePrompt = (styleId) => STYLE_PROMPTS.get(styleId) || null;

export const getStyleOptionSuffix = (styleId, optionId) => {
  const options = STYLE_OPTION_SUFFIXES.get(styleId);
  return options?.get(optionId) || null;
};

// Added for the HINTER "Create" tab — a clean fine-line minimalist tattoo style.
STYLE_PROMPTS.set("fine_line_minimalist", "[SUBJECT]. STYLE: Delicate fine-line minimalist tattoo illustration. Single-needle aesthetic. Elegant, restrained, modern.\nLIGHTING & VALUE: Almost no shading — form is described by line alone. Generous negative space. Where tone exists it is the faintest whisper of stippling, never solid fill.\nCLARITY: Hair-thin, continuous, confident black lines of even weight. Every line deliberate and unbroken. Crisp and clean.\nTEXTURE: Pure black ink on clean white paper. No grain, no smudging, no wash.\nCOMPOSITION: Subject reduced to its essential contours, isolated and centered on a pure white background with airy negative space.\nNEGATIVE: heavy shading, solid black fills, cross-hatching, color, photorealism, 3d, chrome, thick outlines, busy, cluttered, gradients, blurry.");
